    enum State { PresaleLive, SaleLive, SaleClosed }
    State private _currentState = State.PresaleLive;
    uint256 private _presaleAmountMinted;
    uint256 private _publicAmountMinted;
    mapping(address => bool) private _presalerList;

    event WhitelistUpdated(address indexed user, bool indexed status);
    event SaleToggled(State indexed newState);
    event PresaleBuy(address indexed buyer, uint256 amount);
    event Buy(address indexed buyer, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not the owner");
        _;
    }

    constructor() {
        _owner = msg.sender;
    }

    function currentState() public view returns (State) {
        return _currentState;
    }

    function presalerList(address user) public view returns (bool) {
        return _presalerList[user];
    }

    function whitelist(address user, bool status) public onlyOwner {
        _presalerList[user] = status;
        emit WhitelistUpdated(user, status);
    }

    function toggleSale() public onlyOwner {
        if (_currentState == State.PresaleLive) {
            _currentState = State.SaleLive;
        } else if (_currentState == State.SaleLive) {
            _currentState = State.SaleClosed;
        }
        emit SaleToggled(_currentState);
    }

    function presaleBuy() public payable {
        require(_currentState == State.PresaleLive, "Presale is not live");
        require(_presalerList[msg.sender], "Not whitelisted");
        _presaleAmountMinted += msg.value / 1e18; // Convert wei to ETH
        emit PresaleBuy(msg.sender, msg.value);
    }

    function buy() public payable {
        require(_currentState == State.SaleLive, "Sale is not live");
        _publicAmountMinted += msg.value / 1e18; // Convert wei to ETH
        emit Buy(msg.sender, msg.value);
    }

    function presaleAmountMinted() public view returns (uint256) {
        return _presaleAmountMinted;
    }

    function publicAmountMinted() public view returns (uint256) {
        return _publicAmountMinted;
    }
}
